12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Customer = { yearsWithMHPCO: number };
20	type Scenario = { customer: Customer; steps: QuoteStep[] };
21	
22	const BLOCK_SIZE = 3;
23	const BLOCK_PREMIUM = 60;
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	
26	const CURSED_RATE = 0.5;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const HIGH_ENCHANTMENT_RATE = 0.3;
29	
30	type Rule<T> = { applies: (subject: T) => boolean; rate: number };
31	
32	const sumApplicableRates = <T>(rules: Rule<T>[], subject: T): number =>
33	  rules
34	    .filter((rule) => rule.applies(subject))
35	    .reduce((sum, rule) => sum + rule.rate, 0);
36	
37	const isCursed = (item: Item): boolean => item.cursed === true;
38	const isHighlyEnchanted = (item: Item): boolean =>
39	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
40	
41	const SURCHARGE_RULES: Rule<Item>[] = [
42	  { applies: isCursed, rate: CURSED_RATE },
43	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
44	];
45	
46	const groupByType = (items: Item[]): Map<string, Item[]> => {
47	  const groups = new Map<string, Item[]>();
48	  for (const item of items) {
49	    const group = groups.get(item.type) ?? [];
50	    group.push(item);
51	    groups.set(item.type, group);
52	  }
53	  return groups;
54	};
55	
56	const basePremiumFor = (type: string) => BASE_PREMIUM[type];
57	
58	const premiumForGroup = (type: string, group: Item[]) => {
59	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
60	    return BLOCK_PREMIUM;
61	  }
62	  return group.length * basePremiumFor(type);
63	};
64	
65	const itemSurcharges = (item: Item) =>
66	  basePremiumFor(item.type) * sumApplicableRates(SURCHARGE_RULES, item);
67	
68	const policyBasePremium = (items: Item[]) =>
69	  [...groupByType(items)].reduce(
70	    (total, [type, group]) => total + premiumForGroup(type, group),
71	    0,
72	  );
73	
74	const sumItemSurcharges = (items: Item[]) =>
75	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
76	
77	const FIRST_INSURANCE_RATE = 0.1;
78	const LOYALTY_THRESHOLD_YEARS = 2;
79	const LOYALTY_RATE = 0.2;
80	const FOLLOWUP_RATE = 0.15;
81	
82	type QuoteContext = { customer: Customer; stepIndex: number };
83	
84	const POLICY_ADJUSTMENTS: Rule<QuoteContext>[] = [
85	  { applies: () => true, rate: +FIRST_INSURANCE_RATE },
86	  {
87	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
88	    rate: -LOYALTY_RATE,
89	  },
90	  { applies: ({ stepIndex }) => stepIndex > 0, rate: -FOLLOWUP_RATE },
91	];
92	
93	const policyAdjustment = (ctx: QuoteContext, policyBase: number) =>
94	  policyBase * sumApplicableRates(POLICY_ADJUSTMENTS, ctx);
95	
96	const quote = (step: QuoteStep, customer: Customer, stepIndex: number) => {
97	  const policyBase = policyBasePremium(step.items);
98	  const premium =
99	    policyBase +
100	    policyAdjustment({ customer, stepIndex }, policyBase) +
101	    sumItemSurcharges(step.items);
102	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
103	};
104	
105	export const run = (input: Scenario): unknown => ({
106	  results: input.steps.map((step, i) => quote(step, input.customer, i)),
107	});
